/**
 * Chart Component - Dynamic Renderer
 * Generated by script
 */

import React, { lazy, Suspense } from 'react';
// import type { ChartProps, ChartVersion } from '../../types/components/chart.js';

// Fallback types if file doesn't exist
type ChartVersion = string;
interface ChartProps extends React.HTMLAttributes<HTMLElement> {
  version?: ChartVersion;
  variant?: 'neutral' | 'primary' | 'success' | 'warning' | 'destructive' | 'info';
  type?: 'default' | 'outline' | 'solid' | 'ghost';
  [key: string]: any;
}

// Config import
let componentConfig: any = { versions: {} };
try {
  // @ts-ignore
  // componentConfig = require('../../config/components/chart.json');
} catch (e) {
  // console.warn('Config not found for chart');
}

// Dynamic imports for versions
const versionComponents: Record<string, any> = {
  'angular-corner': lazy(() => import('./chart-angular-corner.tsx')),
  'holo-frame': lazy(() => import('./chart-holo-frame.tsx')),
  'data-panel': lazy(() => import('./chart-data-panel.tsx')),
  'circuit-board': lazy(() => import('./chart-circuit-board.tsx')),
  'quantum-gate': lazy(() => import('./chart-quantum-gate.tsx')),
  'tactical-hud': lazy(() => import('./chart-tactical-hud.tsx')),
  'energy-shield': lazy(() => import('./chart-energy-shield.tsx')),
  'terminal-window': lazy(() => import('./chart-terminal-window.tsx')),
  'matrix-grid': lazy(() => import('./chart-matrix-grid.tsx')),
  'neon-outline': lazy(() => import('./chart-neon-outline.tsx')),
};

// Loading Skeleton
const LoadingSkeleton: React.FC = () => (
  <div className="animate-pulse bg-muted/20 w-full h-full min-h-[40px] rounded" />
);

// Fallback Component
const FallbackComponent = React.forwardRef<HTMLElement, ChartProps>(({ 
  children, 
  className = '',
  version,
  ...props 
}, ref) => (
  <div ref={ref as any} className={`p-4 border border-dashed border-red-500/50 bg-red-500/10 ${className}`} {...props}>
    <span className="text-xs text-red-400 font-mono">Missing: {version}</span>
    {children}
  </div>
));
FallbackComponent.displayName = 'FallbackChart';

// Subcomponents

// Main Component
const ChartBase = React.forwardRef<HTMLElement, ChartProps>(({ 
  version = 'angular-corner',
  ...props 
}, ref) => {
  const VersionComponent = versionComponents[version];
  
  if (!VersionComponent) {
    return <FallbackComponent ref={ref} version={version} {...props} />;
  }

  return (
    <Suspense fallback={<LoadingSkeleton />}>
      <VersionComponent ref={ref} {...props} />
    </Suspense>
  );
});
ChartBase.displayName = 'Chart';

export const Chart = ChartBase;

export default Chart;


